insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeux anniversaire. J''ai mémorisé la façon dont chaque invité t''a regardé ce soir.',$$Joyeux anniversaire. J''ai mémorisé la façon dont chaque invité t''a regardé ce soir.
Chacun différemment. Avec affection. Avec admiration. Ces regards portés vers toi quand tu avais le dos tourné. Ces regards qui disent qu''on est content que tu existes. Joyeux anniversaire, mon humain préféré.
Avec collection des regards portés vers toi à ton insu et leur valeur bien pesée, — {prenom}, ton animal gardien des preuves de ton importance 💛$$,'touching',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens partent quand c''est le meilleur moment.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens partent quand c''est le meilleur moment.
Il y avait ce soir un moment parfait. Et quelqu''un a dit je dois y aller. Et ça a tout déclenché. Les manteaux. Les au revoir. Le départ en cascade. Peut-être qu''il faut partir au meilleur moment pour que ça reste bon dans la mémoire. Joyeux anniversaire, mon humain préféré.
Avec théorie du départ au sommet et acceptation progressive de sa sagesse, — {prenom}, ton animal philosophe des fins de soirée 🌅$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de t''appuyer contre le mur quand tu es détendu.',$$Pour ton anniversaire j''ai observé ta façon de t''appuyer contre le mur quand tu es détendu.
C''est un signe. Quand tu t''appuies contre le mur lors d''une conversation c''est que tu es vraiment bien. Que la conversation te tient sans effort. Ton corps confie son poids au mur et ton esprit peut aller plus loin. C''est de la confiance en acte. Joyeux anniversaire, mon humain préféré.
Avec décodage de ta position murale comme signe de confort profond, — {prenom}, ton animal lecteur de tes postures de bien-être 🧍$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé comment tu gères quelqu''un qui parle trop longtemps.',$$Joyeux anniversaire. J''ai observé comment tu gères quelqu''un qui parle trop longtemps.
Avec patience d''abord. Puis tu regardes ailleurs une fraction de seconde. Tu reviens. Tu acquiesces. Tu poses une question qui résume. Puis tu conclus pour les deux. Jamais blessant. Toujours élégant. Joyeux anniversaire, mon humain préféré.
Avec observation de ta technique de clôture conversationnelle et son élégance constante, — {prenom}, ton animal expert en fins de discours 🎯$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé comment tu choisis où t''asseoir dans ta propre maison.',$$Pour ton anniversaire j''ai observé comment tu choisis où t''asseoir dans ta propre maison.
Pas toujours au même endroit. Tu ajustes selon les gens. Tu te mets là où la conversation a besoin de toi. Ou là où quelqu''un semble un peu en retrait. Tu ne choisis pas ton confort en premier. Joyeux anniversaire, mon humain préféré.
Avec décryptage de tes choix de placement et leur motivation systématiquement altruiste, — {prenom}, ton animal admirateur de ta générosité spatiale 🛋️$$,'touching',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai dormi sur ton programme de soirée.',$$Pour ton anniversaire j''ai dormi sur ton programme de soirée.
Cette petite liste sur le comptoir de la cuisine. Les horaires. Les plats. Les choses à ne pas oublier. Je m''y suis installé ce matin avant que tout commence. Elle était encore un projet. Maintenant c''est devenu une belle soirée. Joyeux anniversaire, mon humain préféré.
Avec occupation de la liste matinale et observation de sa transformation en soirée réelle, — {prenom}, ton animal témoin de la naissance des plans 📋$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens prennent des photos de groupe alors qu''ils se voient souvent.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens prennent des photos de groupe alors qu''ils se voient souvent.
Ce soir deux photos de groupe. Peut-être que les photos de groupe ce n''est pas se souvenir des gens. C''est se souvenir d''un moment précis tous ensemble. Joyeux anniversaire, mon humain préféré.
Avec compréhension de la photo de groupe comme capture du moment et non des individus, — {prenom}, ton animal en paix avec cette pratique désormais 📸$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de boire la dernière gorgée.',$$Pour ton anniversaire j''ai observé ta façon de boire la dernière gorgée.
Lentement. Comme si tu savais que c''est la dernière. Tu tiens le verre à la bouche une seconde de plus. Tu poses. Tu regardes au fond. Cette façon de terminer les choses. Entièrement. Avec conscience que c''est la fin de ce verre-là. Joyeux anniversaire, mon humain préféré.
Avec observation de ta façon de finir les choses et admiration pour leur conscience, — {prenom}, ton animal appréciant les fins habitées 🥂$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé comment tu reçois un compliment ce soir.',$$Joyeux anniversaire. J''ai observé comment tu reçois un compliment ce soir.
Quelqu''un t''a dit quelque chose de bien. Tu n''as pas minimisé. Tu n''as pas surjoué. Tu as juste accueilli. C''est rare cette façon de recevoir les bons mots avec grâce. Joyeux anniversaire, mon humain préféré.
Avec observation de ton accueil du compliment et validation de sa justesse parfaite, — {prenom}, ton animal attentif à tes façons de recevoir 🌷$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de regarder l''appartement avant d''aller dormir.',$$Pour ton anniversaire j''ai observé ta façon de regarder l''appartement avant d''aller dormir.
Tu as fait le tour des yeux. Le salon. La cuisine. L''entrée. Pas pour vérifier. Juste pour voir. Pour regarder l''espace qui a été vivant ce soir et qui redevient calme. J''ai fait pareil depuis mon coin. On est pareils toi et moi. Joyeux anniversaire, mon humain préféré.
Avec reconnaissance de notre rituel commun de clôture visuelle et solidarité nocturne, — {prenom}, ton animal co-auteur de ce bonsoir quotidien 🏠$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai mémorisé comment tu sentais ce soir.',$$Joyeux anniversaire. J''ai mémorisé comment tu sentais ce soir.
Pas le parfum. Toi en dessous. Cette odeur qui est la tienne depuis toujours. Mélangée ce soir avec les bougies éteintes. Avec la cuisine. Avec les rires. Une version de toi augmentée de tout ce qui s''est passé. Joyeux anniversaire, mon humain préféré.
Avec mémorisation de ton odeur d''anniversaire dans sa version complète et augmentée, — {prenom}, ton animal archiviste olfactif de tes meilleures soirées 👃$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens disent qu''ils partent et restent encore vingt minutes.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens disent qu''ils partent et restent encore vingt minutes.
On dit je vais y aller. On se lève. On met son manteau. Et puis on reste debout dans l''entrée à continuer à parler vingt minutes. Ces vingt minutes de couloir semblent être les meilleures de la soirée. Joyeux anniversaire, mon humain préféré.
Avec théorie de la conversation de couloir et sa libération liée à la décision de partir, — {prenom}, ton animal fasciné par les entre-deux 🧥$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon d''éteindre les lumières une par une.',$$Pour ton anniversaire j''ai observé ta façon d''éteindre les lumières une par une.
La cuisine d''abord. Puis le couloir. Puis le salon. Une progression qui suit le chemin inverse de la soirée. Ce rituel de fin. Cette façon ordonnée de clore. Joyeux anniversaire, mon humain préféré.
Avec observation du rituel d''extinction et sa progression significative de fin, — {prenom}, ton animal témoin de tes clôtures ordonnées 💡$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé comment tu traites quelqu''un qui arrive en retard.',$$Joyeux anniversaire. J''ai observé comment tu traites quelqu''un qui arrive en retard.
Tu l''accueilles pareil. Pas de regard à la montre. Pas de remarque. Tu lui fais une place. Tu lui résumes brièvement. Tu t''assures qu''il a un verre. Cette façon de ne pas punir les retards. Joyeux anniversaire, mon humain préféré.
Avec admiration pour ton accueil du retard sans punition ni commentaire, — {prenom}, ton animal témoin de ta générosité sans condition 🕰️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de sourire à quelqu''un de dos quand il est parti.',$$Pour ton anniversaire j''ai observé ta façon de sourire à quelqu''un de dos quand il est parti.
La porte s''est fermée. Et toi tu souriais encore. Vers la porte fermée. Ce sourire pour toi seul. Pour ce que la soirée venait de donner. J''étais dans le couloir. J''ai vu. Joyeux anniversaire, mon humain préféré.
Avec observation de ton sourire post-départ et sa valeur de sentiment pur non performé, — {prenom}, ton animal gardien de tes moments non performés 🌟$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai étudié les photos encadrées dans le couloir.',$$Pour ton anniversaire j''ai étudié les photos encadrées dans le couloir.
Celles que tu as depuis des années. Ce soir j''ai pris le temps. Certains visages je les ai reconnus ce soir en vrai. C''était une expérience étrange et belle. Joyeux anniversaire, mon humain préféré.
Avec étude des photos du couloir et expérience de les voir prendre vie en vrai ce soir, — {prenom}, ton animal passeur entre tes souvenirs et ton présent 🖼️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens s''excusent de partir alors qu''ils avaient décidé de partir.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens s''excusent de partir alors qu''ils avaient décidé de partir.
Je dois vraiment y aller maintenant. Comme si partir était une faute. Peut-être que c''est une façon de dire que c''était si bien qu''on regrette de partir. Dans ce cas ce soir valait d''être regretté. Joyeux anniversaire, mon humain préféré.
Avec compréhension de l''excuse du départ comme aveu de la qualité de la soirée, — {prenom}, ton animal herméneute des formules sociales 🎭$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de réajuster les coussins après la fête.',$$Pour ton anniversaire j''ai observé ta façon de réajuster les coussins après la fête.
Chacun à sa place. L''ordre que tu avais choisi et que la soirée avait défait. Cette remise en ordre après. Ces coussins réajustés c''est une lettre à ton futur toi du lendemain. Joyeux anniversaire, mon humain préféré.
Avec décodage du réajustement des coussins comme soin pour le lendemain, — {prenom}, ton animal lecteur de tes gestes de fin 🛋️$$,'touching',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé comment tu t''occupes de quelqu''un qui n''est pas à l''aise.',$$Pour ton anniversaire j''ai observé comment tu t''occupes de quelqu''un qui n''est pas à l''aise.
